import React, { useState } from 'react';

const UserProfile = ({ user }) => {
  const [formData, setFormData] = useState({
    fullName: user.fullName || '',
    address: user.address || '',
    email: user.email || '',
    phoneNumber: user.phoneNumber || '',
  });

  const [passwordData, setPasswordData] = useState({
    oldPass: '',
    newPass: '',
  });

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handlePasswordChange = (e) => {
    setPasswordData({ ...passwordData, [e.target.name]: e.target.value });
  };

  const handleProfileSubmit = (e) => {
    e.preventDefault();
    console.log('Updating profile:', formData);
  };

  const handlePasswordSubmit = (e) => {
    e.preventDefault();
    console.log('Changing password:', passwordData);
  };

  return (
    <div className="user-profile">
      <div className="container-xl px-4 mt-4">
        <div className="row">
          <div className="col-xl-4">
            <div className="card mb-4 mb-xl-0">
              <div className="card-header">Ảnh đại diện</div>
              <div className="card-body text-center">
                <img
                  className="img-account-profile rounded-circle mb-2"
                  src={`/assets/images/user-profile/${user.avatar}`}
                  style={{ width: 160, height: 160 }}
                  alt={`Ảnh đại diện ${user.avatar}`}
                />
                <div className="small font-italic text-muted mb-4">JPG hoặc PNG không lớn hơn 5 MB</div>
                <input type="file" id="avatar" style={{ display: 'none' }} accept="image/*" />
                <label htmlFor="avatar" className="btn btn-primary">Tải ảnh lên</label>
              </div>
            </div>
            <div className="card mb-4 mb-xl-0">
              <button className="btn btn-primary">Đổi mật khẩu</button>
            </div>
          </div>

          <div className="col-xl-8">
            <div className="card mb-4">
              <div className="card-header">Thông tin tài khoản</div>
              <div className="card-body">
                <form onSubmit={handleProfileSubmit}>
                  <div className="row gx-3 mb-3">
                    <div className="col-md-12">
                      <label className="small mb-1">Họ và tên</label>
                      <input
                        className="form-control"
                        name="fullName"
                        type="text"
                        value={formData.fullName}
                        onChange={handleChange}
                        required
                      />
                    </div>
                  </div>

                  <div className="row gx-3 mb-3">
                    <div className="col-md-12">
                      <label className="small mb-1">Địa chỉ</label>
                      <input
                        className="form-control"
                        name="address"
                        type="text"
                        value={formData.address}
                        onChange={handleChange}
                        required
                      />
                    </div>
                  </div>

                  <div className="mb-3">
                    <label className="small mb-1">Email</label>
                    <input
                      className="form-control"
                      name="email"
                      type="email"
                      value={formData.email}
                      onChange={handleChange}
                      required
                    />
                  </div>

                  <div className="row gx-3 mb-3">
                    <div className="col-md-6">
                      <label className="small mb-1">Số điện thoại</label>
                      <input
                        className="form-control"
                        name="phoneNumber"
                        type="tel"
                        value={formData.phoneNumber}
                        onChange={handleChange}
                        required
                      />
                    </div>
                  </div>

                  <button className="btn btn-primary" type="submit">Lưu thông tin</button>
                </form>
              </div>
            </div>

            <div className="card mb-4">
              <div className="card-body">
                <form onSubmit={handlePasswordSubmit}>
                  <div className="row gx-3">
                    <div className="col-md-4">
                      <input
                        className="form-control"
                        name="oldPass"
                        type="password"
                        placeholder="Nhập mật khẩu cũ"
                        value={passwordData.oldPass}
                        onChange={handlePasswordChange}
                        required
                      />
                    </div>
                    <div className="col-md-4">
                      <input
                        className="form-control"
                        name="newPass"
                        type="password"
                        placeholder="Nhập mật khẩu mới"
                        value={passwordData.newPass}
                        onChange={handlePasswordChange}
                        required
                      />
                    </div>
                    <div className="col-md-4">
                      <button className="btn btn-primary" type="submit">Thay đổi</button>
                    </div>
                  </div>
                </form>
              </div>
            </div>

          </div>
        </div>
      </div>
    </div>
  );
};

export default UserProfile;
